package main

import (
	"fmt"
	"os"
	"os/exec"
	"strings"
)

func main() {
	dependencies := []string{
		"github.com/gin-gonic/gin@latest",
		"github.com/spf13/cobra@latest",
		"golang.org/x/tools/cmd/goimports@latest",
	}

	fmt.Println("Installing Go dependencies...")

	env := os.Environ()
	goModuleEnabled := true
	for _, e := range env {
		if strings.HasPrefix(e, "GO111MODULE=") {
			if strings.Contains(e, "off") {
				goModuleEnabled = false
			}
			break
		}
	}

	if !goModuleEnabled {
		fmt.Println("Warning: GO111MODULE is not enabled. Enabling modules for secure dependency management.")
		env = append(env, "GO111MODULE=on")
	}

	var filteredEnv []string
	for _, e := range env {
		if !strings.HasPrefix(e, "GOPRIVATE=") &&
			!strings.HasPrefix(e, "GOSUMDB=") &&
			!strings.HasPrefix(e, "GONOSUMDB=") {
			filteredEnv = append(filteredEnv, e)
		}
	}

	if privateRepos := os.Getenv("GOPRIVATE"); privateRepos != "" {
		filteredEnv = append(filteredEnv, "GOPRIVATE="+privateRepos)
		fmt.Printf("Using GOPRIVATE for internal repositories: %s\n", privateRepos)
	}

	filteredEnv = append(filteredEnv, "GOSUMDB=sum.golang.org")

	for _, dep := range dependencies {
		fmt.Printf("Installing %s...\n", dep)

		cmd := exec.Command("go", "get", dep)
		cmd.Env = filteredEnv
		cmd.Stdout = os.Stdout
		cmd.Stderr = os.Stderr

		if err := cmd.Run(); err != nil {
			fmt.Fprintf(os.Stderr, "Error installing %s: %v\n", dep, err)
			os.Exit(1)
		}
	}

	fmt.Println("\nRunning go mod tidy to clean up dependencies...")
	tidyCmd := exec.Command("go", "mod", "tidy")
	tidyCmd.Env = filteredEnv
	tidyCmd.Stdout = os.Stdout
	tidyCmd.Stderr = os.Stderr

	if err := tidyCmd.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "Error running go mod tidy: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("\nVerifying dependencies...")
	verifyCmd := exec.Command("go", "mod", "verify")
	verifyCmd.Env = filteredEnv
	verifyCmd.Stdout = os.Stdout
	verifyCmd.Stderr = os.Stderr

	if err := verifyCmd.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "Warning: Dependency verification failed: %v\n", err)
		fmt.Println("Please review go.sum for integrity issues")
	}

	fmt.Println("\nDependency installation complete!")
	fmt.Println("Security recommendations:")
	fmt.Println("- Review go.sum file and commit it to version control")
	fmt.Println("- Use GOPRIVATE only for genuinely private repositories")
	fmt.Println("- Ensure all dependencies are from trusted sources")
	fmt.Println("- Consider using a dependency proxy or mirror for corporate environments")
}